create table if not exists public.study_memos (
  id uuid primary key,
  title text not null default '無題のメモ',
  body text not null default '',
  created_at timestamptz not null,
  updated_at timestamptz not null
);

create index if not exists study_memos_updated_at_idx
  on public.study_memos (updated_at desc);

alter table public.study_memos disable row level security;
grant usage on schema public to anon;
grant select, insert, update, delete on public.study_memos to anon;

with seed(data) as (
  values (
    $memo_seed$[{"id":"1e2bb869-7212-45ce-b787-43911c041171","title":"Azure Monitor Private Link Scope","body":"・Azure Monitor リソースをまとめるスコープ\n\n        +---------------------+\n        | Workspace1          |\n        | Log Analytics       |\n        +----------+----------+\n                   ^\n                   |\n                   | Private Link 経由でログ送信\n                   |\n        +----------+----------+\n        | AMPLS               |\n        | Workspace1を含む箱   |\n        +----------+----------+\n                   ^\n                   |\n       +-----------+-------------+\n       |                         |\nPrivate Endpoint            Private Endpoint\nfor VNet1/VNet2             for VNet3\n       |                         |\n       v                         v\n+-------------+           +-------------+\n| VNet1       |           | VNet3       |\n| VMs         |           | VMs         |\n+------+------+           +-------------+\n       |\n       | VNet peering\n       |\n+-------------+\n| VNet2       |\n| VMs         |\n+-------------+","createdAt":"2026-06-08T10:38:33.792Z","updatedAt":"2026-06-08T10:39:53.190Z"},{"id":"28360403-1fdf-4e7b-9ca7-4c0f1df30220","title":"Azure Data Studio","body":"・Azure SQL Migration 拡張を使い、Azure SQL Managed Instance への移行を支援","createdAt":"2026-06-08T10:31:55.354Z","updatedAt":"2026-06-08T10:32:33.756Z"},{"id":"eba0eacd-141a-4502-bc10-bf300f00ee96","title":"SQL Server / DB 移行系のツールの全体像","body":"移行計画・評価\n  ↓\nAzure Migrate / DMA\n\n実際のDB移行\n  ↓\nAzure Database Migration Service\n\n異種DBからSQL系への変換\n  ↓\nSSMA\n\nAzure Migrate\n= 移行全体の評価・計画ハブ\n\nDMS\n= DBを実際にAzureへ移行するサービス\n\nSSMA\n= Oracle / MySQL / Access / DB2 など異種DBからSQL Server系へ変換・移行\n\nDMA\n= SQL Server移行前の互換性評価・問題検出","createdAt":"2026-06-08T10:17:14.753Z","updatedAt":"2026-06-08T10:25:46.664Z"},{"id":"ab51aa96-e9e5-43bf-aef7-01b53560dffd","title":"Data Migration Assistant, DMA","body":"## 概要\n・SQL Server 移行前の評価・互換性確認に使うツール\n・略称は DMA\n・SQL Server から Azure SQL Database / Azure SQL Managed Instance へ移す前に、互換性の問題や移行ブロッカーを確認するために使う\n\n## 特徴\n・移行前評価に強い\n・互換性レベルの問題を検出する\n・非推奨機能や破壊的変更の可能性を確認する\n・Azure SQL Database / Managed Instance への移行可否を確認する\n・移行計画段階で使う\n・実際の大規模移行をマネージドに実行する主役ではない\n・「評価」は DMA、「実行」は DMS と覚えるとよい\n\n## 覚え方\n移行できるか調べる\n互換性問題を見つける\n        ↓\nDMA\n\n実際に移行する\n        ↓\nDMS","createdAt":"2026-06-08T10:24:10.510Z","updatedAt":"2026-06-08T10:25:22.937Z"},{"id":"353ddbfc-4de1-4012-b283-f7543f246b61","title":"SQL Server Migration Assistant, SSMA","body":"## 概要\n・異種データベースから SQL Server / Azure SQL 系へ移行するためのツール\n・略称は SSMA\n\n## 特徴\n・Oracle、MySQL、Db2、Access、SAP ASE などから SQL Server 系へ移行する場合に使う\n・異種 DB のスキーマやオブジェクトを SQL Server / Azure SQL 向けに変換する\n・テーブル、ビュー、ストアドプロシージャ、関数などの変換が関係する\n・移行前の評価にも使える\n・「SQL Server から Azure SQL へ」ではなく、「Oracle から Azure SQL」などの文脈で出やすい\n・SQL Server から Azure SQL への移行では、基本的にソースとターゲットが同じ SQL Server 系なので、異種 DB 変換が主目的ではない\n\n## 選ぶべきケース\n・Oracle Database を Azure SQL Managed Instance に移行したい\n・MySQL のスキーマを SQL Server 用に変換したい\n・Access DB を Azure SQL Database に移行したい\n・異なる DB エンジンから SQL Server 系へ移したい\n・T-SQL 互換ではないオブジェクトを変換したい","createdAt":"2026-06-08T10:22:57.335Z","updatedAt":"2026-06-08T10:24:05.761Z"},{"id":"509ec81b-120e-439a-a652-ebc1a4688d08","title":"Azure Migrate","body":"## 概要\n・Azure 移行全体の計画・評価・管理ハブ\n・サーバー、データベース、Web アプリ、仮想デスクトップなど、Azure への移行を評価・計画・実行するためのサービス群の入口\n\n## 特徴\n・移行プロジェクト全体を管理するハブ\n・オンプレミス環境の検出に使う\n・Azure への移行準備状況を評価できる\n・Azure 上での推定コストを見積もれる\n・サーバー移行、DB 移行、Web アプリ移行などを広く扱う\n・SQL Server インスタンスを Azure SQL Database / Azure SQL Managed Instance / SQL Server on Azure VM に移行するための推奨ターゲットや準備状況を確認できる\n・ただし、試験で「SQL Server DB を MI に移行する実行サービスは？」と聞かれたら、より直接的なのは Azure DMS\n\n## 選ぶべきケース\n・オンプレミス環境をまず検出・評価したい\n・Azure に移行できるか確認したい\n・移行後のサイズやコストを見積もりたい\n・VM、DB、Web アプリなど移行対象が複数種類ある\n・移行プロジェクト全体を管理したい\n\n## 覚え方\n移行前に調べる・評価する・計画する\n        ↓\nAzure Migrate","createdAt":"2026-06-08T10:21:30.395Z","updatedAt":"2026-06-08T10:22:52.175Z"},{"id":"4b447f91-0920-4044-9f0c-9664f758279f","title":"Azure Database Migration Service","body":"## 概要\n・データベース移行を実行するためのマネージドサービス\n・略称は Azure DMS\n・SQL Server から Azure SQL Database / Azure SQL Managed Instance / SQL Server on Azure VM などへの移行で使う\n・オフライン移行とオンライン移行の両方をサポートします。オフライン移行では移行開始時点からアプリケーション停止時間が発生し、オンライン移行では最後の切り替え時点に停止時間を抑えられます。\n\n## 特徴\n・SQL Server から Azure SQL Managed Instance への移行に向く\n・複数データベースの移行をまとめて扱いやすい\n・Azure ポータル、PowerShell、Azure CLI から利用できる\n・オフライン移行に対応\n・オンライン移行、つまり最小ダウンタイム移行にも対応するシナリオがある\n・移行作業を Azure 側のサービスとして管理できるため、手作業や個別スクリプトより管理オーバーヘッドを抑えやすい\n・既存 SQL Server から Azure SQL 系へ移す「本番移行の実行役」として覚える\n\n## 選ぶべきケース\n・オンプレミス SQL Server の DB を Azure SQL Managed Instance に移行する\n・複数 DB をまとめて Azure へ移行する\n・移行処理をマネージドに実行したい\n・オフライン移行またはオンライン移行を選びたい\n・移行対象が SQL Server 系で、変換より「移行実行」が主目的\n\n## 覚え方\nDBを実際にAzureへ移す\n+ SQL Server → Azure SQL Managed Instance\n+ オフライン/オンライン移行\n+ 管理オーバーヘッド最小\n        ↓\nAzure Database Migration Service","createdAt":"2026-06-08T10:18:14.388Z","updatedAt":"2026-06-08T10:20:56.807Z"},{"id":"4630eb49-acb1-4382-8310-0fabcbfcd2ef","title":"Azure SQL 系の大枠","body":"Azure SQL 系の大枠\n\nAzure SQL\n├─ Azure SQL Database\n│   ├─ 単一データベース\n│   └─ エラスティック プール\n│\n├─ Azure SQL Managed Instance\n│\n└─ SQL Server on Azure VM\n\n## 試験向けの選び分け早見表\n要件\t選ぶもの\n・1つの DB を PaaS で使いたい\tAzure SQL Database 単一データベース\n・自動スケール、秒単位課金、自動停止\tAzure SQL Database 単一 DB + Serverless\n・複数 DB でリソース共有\tAzure SQL Database エラスティック プール\n・SaaS で顧客ごとに DB がある\tエラスティック プール\n・SQL Server 互換性を重視して PaaS 移行\tAzure SQL Managed Instance\n・SQL Server Agent などインスタンス機能が必要\tAzure SQL Managed Instance\n・OS レベルの制御が必要\tSQL Server on Azure VM\n・既存 SQL Server を最小変更で lift-and-shift\tSQL Server on Azure VM または Managed Instance\n・管理オーバーヘッドを最小化\tAzure SQL Database\n・巨大 DB、ストレージ大規模拡張\tHyperscale\n・重要業務、高 I/O、低レイテンシ\tBusiness Critical\n・一般的な業務アプリ、コスト重視\tGeneral Purpose","createdAt":"2026-06-08T09:43:27.000Z","updatedAt":"2026-06-08T09:58:55.666Z"},{"id":"48b3018b-9c10-4a2f-97af-f47d17871a37","title":"Azure SQL Database の購入 レベル","body":"# DTU モデル\n・DTU は Database Transaction Unit の略\n・CPU、メモリ、I/O をまとめた抽象的な性能単位\n・Basic、Standard、Premium などの階層で出ることがある\n・シンプルに選びたい場合に向く\n・ただし、試験では最近は vCore、Serverless、Hyperscale などの文脈の方が出やすい印象です\n\n# vCore モデル\n・仮想コア数、メモリ、ストレージをより明示的に選ぶモデル\n・Azure ハイブリッド特典など、ライセンス最適化の文脈で出やすい\n・General Purpose、Business Critical、Hyperscale と組み合わせて問われやすい\n・リソース構成を理解しやすい\n・既存 SQL Server ライセンスを活用する設計問題で候補になりやすい\n\n## 覚え方\n簡単に性能単位を選びたい\n        ↓\nDTU\n\nCPU/メモリ/ストレージ/ライセンスを意識したい\n        ↓\nvCore","createdAt":"2026-06-08T09:55:37.030Z","updatedAt":"2026-06-08T09:56:41.832Z"},{"id":"f1decea8-e17c-4b8f-bf33-25a76dbbf369","title":"Azure SQL Database のサービス レベル","body":"ここからは「製品」ではなく、主に 性能/可用性/ストレージの階層です。\n\nAzure SQL Database の vCore 購入モデルでは、主なサービス レベルとして General Purpose、Business Critical、Hyperscale があります。\nサービス レベルは、ストレージ、性能、高可用性、DR オプション、特定機能の可用性を決めます。\n\n# General Purpose\n## 概要\n・汎用的なワークロード向け\n・コストと性能のバランス型\n・多くの標準的な業務アプリで候補になる\n\n## 特徴\n・一般的なビジネスアプリ向け\n・コストを抑えたい場合に選びやすい\n・超低レイテンシや非常に高い I/O 要件がなければ候補\n・サーバーレスを使う場合にもよく出る\n・「特別な高性能要件がない」ならまず候補\n\n## 試験での覚え方\n普通の業務DB + コスト重視\n        ↓\nGeneral Purpose\n\n# Business Critical\n## 概要\n・高い I/O 性能、低レイテンシ、高可用性が必要な重要業務向け\n・より高性能なストレージ構成や可用性構成を使う階層\n\n## 特徴\n・ミッションクリティカルな OLTP に向く\n・高いトランザクション性能が必要な DB に向く\n・低レイテンシが重要な場合に候補\n・General Purpose より高コスト\n・高可用性や読み取りスケールが問われる問題で出やすい\n\n## 試験での覚え方\n重要業務 + 高IO + 低レイテンシ\n        ↓\nBusiness Critical\n\n# Hyperscale\n## 概要\n・大容量 DB、急速なスケール、バックアップ/復元性能を重視する階層\n・Microsoft Learn では、Hyperscale は高い性能と可用性、高速なバックアップ/復元、高速なストレージ/コンピューティング スケーラビリティが必要な顧客向けと説明されています。\n\n## 特徴\n・非常に大きなデータベースに向く\n・ストレージを大きく拡張しやすい\n・高速なバックアップ/復元が求められる場合に候補\n・読み取りスケールアウトが必要な場合にも出やすい\n・大規模 OLTP、分析寄りの読み取り負荷など幅広いワークロードに対応\n\n## 試験での覚え方\n巨大DB + 高速バックアップ/復元 + 大規模スケール\n        ↓\nHyperscale","createdAt":"2026-06-08T09:52:32.980Z","updatedAt":"2026-06-08T09:54:47.167Z"},{"id":"019d1b9b-9824-4fa9-8bfa-8e4bbae0856d","title":"SQL Server on Azure VM","body":"## 概要\n・Azure VM 上に SQL Server をインストールして使う IaaS\n・ほぼ従来の SQL Server サーバーをクラウド VM 上で動かすイメージ\n\n## 特徴\n・OS レベルの制御ができる\n・SQL Server インスタンスの管理自由度が最も高い\n・SQL Server の設定、OS 設定、ディスク構成などを細かく制御できる\n・既存環境を lift-and-shift しやすい\n・その代わり、VM、OS、SQL Server の運用責任が増える\n・SQL IaaS Agent 拡張機能を使うと、ポータル管理、自動バックアップ、自動パッチ適用など一部の管理支援を受けられる。\n・SQL Database や Managed Instance よりも管理オーバーヘッドは大きい\n\n## 覚え方\nOSもSQL Serverも完全に触りたい\n        ↓\nSQL Server on Azure VM","createdAt":"2026-06-08T09:51:25.485Z","updatedAt":"2026-06-08T09:52:16.059Z"},{"id":"e281addc-8c28-469b-95b3-ed95c122e18f","title":"Azure SQL マネージド インスタンス","body":"## 概要\n・SQL Server インスタンスに近い PaaS\n・オンプレミス SQL Server からの移行に向く\n・Azure SQL Database よりも SQL Server 互換性が高い\n\n## 特徴\n・SQL Server インスタンス単位の機能が必要な場合に向く\n・オンプレミス SQL Server からの移行でアプリ改修を少なくしたい場合に向く\n・SQL Server Agent など、インスタンスレベル機能を使う移行シナリオで候補になる\n・PaaS なので、VM より管理負荷は低い\n・OS 管理や SQL Server のパッチ管理は Azure 側に寄せられる\n・通常、VNet 統合された構成で使う\n・単一データベースよりも「SQL Server インスタンス全体を Azure に持っていく」イメージに近い\n\n## 選ぶべきケース\n・既存の SQL Server アプリを大きく変えずに Azure へ移行したい\n・単一 DB では足りない SQL Server 互換機能が必要\n・SQL Server インスタンス単位の移行をしたい\n・VM ほどの OS 管理はしたくない\n・PaaS の運用メリットも欲しい\n\n## 覚え方\nSQL Server 互換性重視 + 移行 + PaaS\n        ↓\nAzure SQL Managed Instance","createdAt":"2026-06-08T09:43:01.748Z","updatedAt":"2026-06-08T09:51:16.683Z"},{"id":"4e2eccfe-591f-43a8-b337-019c52afdf75","title":"Azure SQL データベース エラスティック プール","body":"## 概要\n・複数の Azure SQL Database がリソースを共有する仕組み\n・複数 DB の使用量がばらつく場合に、全体としてコストを最適化する\n\n## 特徴\n・複数データベースで vCore や DTU などのリソースを共有する\n・各 DB の負荷ピークが同時に来ない場合にコスト効率がよい\n・SaaS 型アプリでよく使われる\n例: 顧客ごとに DB を分けるマルチテナント SaaS\nプール全体に対してリソースを割り当てる\n各 DB が必要なときだけプール内のリソースを使う\n\n## 選ぶべきケース\n・100個、1,000個など多数の DB を管理する\n・各 DB の使用量がばらつく\n・すべての DB に個別リソースを割り当てると高コスト\n・SaaS アプリで顧客ごとに DB を分ける\n・複数 DB 全体で予算を管理したい\n\n## 覚え方\n複数DB + 使用量ばらばら + リソース共有 + SaaS\n        ↓\nAzure SQL Database エラスティック プール","createdAt":"2026-06-08T09:42:50.348Z","updatedAt":"2026-06-08T09:49:55.466Z"},{"id":"91d7830b-a18c-4af3-84f1-7105f08ff8fe","title":"単一Azure SQL データベース","body":"## 概要\n・1つのデータベースを PaaS として使うサービス\n・Azure SQL 系で最も基本的な選択肢\n・OS、SQL Server エンジンのパッチ適用、バックアップ、高可用性などは Azure 側が管理する\n\n## 特徴\n・アプリケーションごとに独立したデータベースを持たせたい場合に向く\n・クラウドネイティブな新規アプリケーションに向く\n・データベース単位で性能を調整できる\n・サーバー管理、OS 管理、SQL Server インスタンス管理は不要\n・パッチ適用や基盤管理の運用負荷が小さい\n・単一 DB を後からエラスティック プールに入れたり、逆にプールから外したりできる。\n\n## 選ぶべきケース\n・新規アプリの DB を Azure に作りたい\n・SQL Server の OS やインスタンス管理をしたくない\n・1つの DB 単位で性能やコストを管理したい\n・ワークロードが断続的で、使っていない時間のコストを抑えたい\n・自動スケール + 秒単位課金が必要\n\n1アプリ / 1DB / PaaS / 管理少なめ\n        ↓\nAzure SQL Database 単一データベース","createdAt":"2026-06-08T09:42:36.413Z","updatedAt":"2026-06-08T09:46:38.554Z"},{"id":"280c9057-2124-415a-8feb-c009a6a8710a","title":"Azure Traffic Manager","body":"・DNS ベースのグローバル負荷分散サービスであり、VMSS への受信トラフィックを NVA に流すインライン分散には対応しません。\n・クライアントからの DNS 問い合わせに対して、適切なエンドポイントの DNS 名または IP を返す\n・主な用途は以下です。\n複数リージョン間の分散\nリージョン障害時のフェールオーバー\nレイテンシベースルーティング\n優先順位ルーティング\n重み付けルーティング\n地理的ルーティング\n実際の通信パケットを中継しない\nDNS 応答で接続先を案内するだけ","createdAt":"2026-06-08T09:39:50.784Z","updatedAt":"2026-06-08T09:40:55.488Z"},{"id":"c038d3d2-d148-4db9-b01a-fef204da4f07","title":"Azure Application Gateway","body":"・L7 Web アプリケーション負荷分散向けで、NVA への透過的な挿入には Gateway Load Balancer が適しています。","createdAt":"2026-06-08T09:39:32.868Z","updatedAt":"2026-06-08T09:39:45.133Z"},{"id":"9792a0b3-61c5-4ba2-aabe-ad93e99c89b1","title":"Azure Front Door","body":"・グローバル HTTP/HTTPS アプリ配信や WAF 向けで、NVA へのインライン分散には使いません。","createdAt":"2026-06-08T09:39:18.440Z","updatedAt":"2026-06-08T09:39:27.582Z"},{"id":"d6812047-64b0-410d-9548-a9a499c3ffa9","title":"Gateway Load Balancer","body":"・NVA の高可用性、スケール、透過的なトラフィック挿入を目的とした Azure Load Balancer の SKU ","createdAt":"2026-06-08T09:38:58.716Z","updatedAt":"2026-06-08T09:39:10.567Z"},{"id":"81e9cee3-0e0a-46c1-946f-ef416d04e40d","title":"Azure Data Share","body":"・組織間でデータを共有するサービス、組織間で Azure データを安全に共有し、スナップショット ベースの共有を管理\n・共有には向くが、VM 上の SQL Server からの取り込み・変換には弱い","createdAt":"2026-06-08T09:32:09.914Z","updatedAt":"2026-06-08T09:34:19.858Z"},{"id":"a49ef02a-9611-47d1-bebf-16e7a9c03a15","title":"Azure Synapse パイプライン","body":"・データのコピー、変換、スケジュール、ワークフロー実行\n・外部データの取り込み、変換、Data Lake への格納を一連のパイプラインとして実装可能","createdAt":"2026-06-08T09:32:44.218Z","updatedAt":"2026-06-08T09:33:10.491Z"},{"id":"1ce1558b-c74f-4a4d-9d5b-f49d267789eb","title":"Azure Data Box Gateway","body":"・オンプレミスと Azure 間のデータ転送を支援するアプライアンス\n・大量データを Azure Storage へ転送するストレージゲートウェイ\n・転送には使えるが、SQL 抽出や変換ワークフローの中心ではない","createdAt":"2026-06-08T09:31:04.022Z","updatedAt":"2026-06-08T09:32:01.369Z"}]$memo_seed$::jsonb
  )
)
insert into public.study_memos (id, title, body, created_at, updated_at)
select
  memo.id,
  coalesce(nullif(btrim(memo.title), ''), '無題のメモ'),
  coalesce(memo.body, ''),
  memo."createdAt",
  memo."updatedAt"
from seed
cross join jsonb_to_recordset(seed.data) as memo(
  id uuid,
  title text,
  body text,
  "createdAt" timestamptz,
  "updatedAt" timestamptz
)
on conflict (id) do update set
  title = excluded.title,
  body = excluded.body,
  created_at = excluded.created_at,
  updated_at = excluded.updated_at;
